mapper.select:
SELECT o.order_seq AS orderSeq, o.order_no AS orderNo, st.company_name AS companyName, o.total_amount AS totalAmount, o.status AS status, o.created_at AS createdAt, o.zonecode AS zonecode, o.address1 AS address1, o.address2 AS address2, o.order_memo AS orderMemo FROM orders o JOIN stores st ON o.buyer_seq = st.user_seq WHERE o.seller_seq = #{sellerSeq}
AND o.status = #{status}
AND ( o.order_no LIKE CONCAT('%', #{keyword}, '%') OR st.company_name LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY o.order_seq DESC

mapper.update:
UPDATE orders
SET status = #{status}
WHERE order_seq = #{orderSeq}

mapper.select:
SELECT buyer_seq
FROM orders
WHERE order_seq = #{orderSeq}
